1	{
2	  "$schema": "https://json.schemastore.org/tsconfig",
3	  "extends": "./base.json",
4	  "compilerOptions": {
5	    "lib": ["ES2022", "dom", "dom.iterable"],
6	    "jsx": "preserve",
7	    "plugins": [
8	      {
9	        "name": "next"
10	      }
11	    ]
12	  },
13	  "exclude": ["node_modules"]
14	}
15

1	/**
2	 * Capture Script
3	 *
4	 * Queries `gateway_webhook_deliveries` for real webhook payloads,
5	 * sanitizes PII, and writes one fixture file per {eventType}.{action}.json.
6	 *
7	 * Usage:
8	 *   cd packages/webhook-schemas && pnpm capture
9	 */
10	
11	import { mkdirSync, writeFileSync } from "node:fs";
12	import { join } from "node:path";
13	import { db } from "@db/app/client";
14	import { gatewayWebhookDeliveries } from "@db/app/schema";
15	import { and, isNotNull, sql } from "drizzle-orm";
16	
17	// ── Types ───────────────────────────────────────────────────────────────────
18	
19	type JsonValue =
20	  | string
21	  | number
22	  | boolean
23	  | null
24	  | JsonValue[]
25	  | { [key: string]: JsonValue };
26	
27	// ── PII Sanitization ────────────────────────────────────────────────────────
28	
29	const AUTHOR_CONTEXT_KEYS = new Set(["author", "committer", "co-authored-by"]);
30	
31	function isAuthorContext(key: string): boolean {
32	  const lower = key.toLowerCase();
33	  return AUTHOR_CONTEXT_KEYS.has(lower);
34	}
35	
36	function walk(
37	  obj: Record<string, JsonValue>,
38	  parentKey = ""
39	): Record<string, JsonValue> {
40	  for (const [key, value] of Object.entries(obj)) {
41	    if (key === "avatar_url" && typeof value === "string") {
42	      obj[key] = "https://avatars.githubusercontent.com/u/0";
43	      continue;
44	    }
45	
46	    if (key === "email" && typeof value === "string") {
47	      obj[key] = "redacted@example.com";
48	      continue;
49	    }
50	
51	    if (
52	      key === "name" &&
53	      typeof value === "string" &&
54	      isAuthorContext(parentKey)
55	    ) {
56	      obj[key] = "Redacted User";
57	      continue;
58	    }
59	
60	    // Vercel meta field
61	    if (key === "githubCommitAuthorName" && typeof value === "string") {
62	      obj[key] = "Redacted User";
63	      continue;
64	    }
65	
66	    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
67	      walk(value as Record<string, JsonValue>, key);
68	    } else if (Array.isArray(value)) {
69	      for (const item of value) {
70	        if (item !== null && typeof item === "object" && !Array.isArray(item)) {
71	          walk(item as Record<string, JsonValue>, key);
72	        }
73	      }
74	    }
75	  }
76	  return obj;
77	}
78	
79	function sanitize(
80	  payload: Record<string, JsonValue>
81	): Record<string, JsonValue> {
82	  const clone = structuredClone(payload);
83	  return walk(clone);
84	}
85	
86	// ── Derive action from payload ──────────────────────────────────────────────
87	
88	function deriveAction(
89	  provider: string,
90	  eventType: string,
91	  payload: Record<string, JsonValue>
92	): string {
93	  if (provider === "github") {
94	    const action = payload.action;
95	    if (typeof action === "string") {
96	      return `${eventType}.${action}`;
97	    }
98	    return eventType;
99	  }
100	
101	  if (provider === "vercel") {
102	    // eventType is already like "deployment.created"
103	    return eventType;
104	  }
105	
106	  return eventType;
107	}
108	
109	// ── Main ────────────────────────────────────────────────────────────────────
110	
111	async function main() {
112	  console.log("Querying gateway_webhook_deliveries...\n");
113	
114	  const rows = await db
115	    .select({
116	      provider: gatewayWebhookDeliveries.provider,
117	      eventType: gatewayWebhookDeliveries.eventType,
118	      payload: gatewayWebhookDeliveries.payload,
119	      receivedAt: gatewayWebhookDeliveries.receivedAt,
120	    })
121	    .from(gatewayWebhookDeliveries)
122	    .where(
123	      and(
124	        isNotNull(gatewayWebhookDeliveries.payload),
125	        sql`${gatewayWebhookDeliveries.provider} IN ('github', 'vercel')`
126	      )
127	    )
128	    .orderBy(gatewayWebhookDeliveries.receivedAt)
129	    .limit(100);
130	
131	  console.log(`Found ${rows.length} rows with payloads\n`);
132	
133	  // Group by provider + action, keep first (oldest) per group
134	  const grouped = new Map<string, Record<string, JsonValue>>();
135	  const providerCounts: Record<string, number> = {};
136	
137	  for (const row of rows) {
138	    if (!row.payload) {
139	      continue;
140	    }
141	
142	    let parsed: Record<string, JsonValue>;
143	    try {
144	      parsed = JSON.parse(row.payload) as Record<string, JsonValue>;
145	    } catch {
146	      console.log(
147	        `  Skipping unparseable payload for ${row.provider}/${row.eventType}`
148	      );
149	      continue;
150	    }
151	
152	    const action = deriveAction(row.provider, row.eventType, parsed);
153	    const key = `${row.provider}:${action}`;
154	
155	    if (!grouped.has(key)) {
156	      grouped.set(key, sanitize(parsed));
157	      providerCounts[row.provider] = (providerCounts[row.provider] ?? 0) + 1;
158	    }
159	  }
160	
161	  // Write fixtures
162	  const fixturesDir = join(import.meta.dirname, "..", "fixtures");
163	
164	  for (const [key, payload] of grouped) {
165	    const colonIdx = key.indexOf(":");
166	    const provider = key.slice(0, colonIdx);
167	    const eventAction = key.slice(colonIdx + 1);
168	
169	    const dir = join(fixturesDir, provider);
170	    mkdirSync(dir, { recursive: true });
171	
172	    const filePath = join(dir, `${eventAction}.json`);
173	    writeFileSync(filePath, `${JSON.stringify(payload, null, 2)}\n`);
174	  }
175	
176	  // Summary
177	  console.log("Fixtures written:");
178	  for (const [provider, count] of Object.entries(providerCounts)) {
179	    console.log(`  ${provider}: ${count} fixture(s)`);
180	  }
181	  console.log(`\nTotal: ${grouped.size} fixture file(s)`);
182	
183	  // List all written files
184	  console.log("\nFiles:");
185	  for (const key of grouped.keys()) {
186	    const colonIdx = key.indexOf(":");
187	    const provider = key.slice(0, colonIdx);
188	    const eventAction = key.slice(colonIdx + 1);
189	    console.log(`  fixtures/${provider}/${eventAction}.json`);
190	  }
191	
192	  process.exit(0);
193	}
194	
195	main().catch((err) => {
196	  console.error("Capture failed:", err);
197	  process.exit(1);
198	});
