import { mkdirSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { db } from "@db/app/client";
import { gatewayWebhookDeliveries } from "@db/app/schema";
import { and, isNotNull, sql } from "drizzle-orm";

